import React from 'react';
import { Pressable, StyleSheet, Text, View } from 'react-native';

import { V } from '../constants/vinlandTheme';
import type { ExerciseDefinition } from '../types';
import { exerciseSummaryLines } from '../utils/workouts';

type TaskItemProps = {
  name: string;
  completed: boolean;
  onToggle: () => void;
  exercise?: ExerciseDefinition;
};

export function TaskItem({
  name,
  completed,
  onToggle,
  exercise,
}: TaskItemProps) {
  const detailLines = exercise ? exerciseSummaryLines(exercise) : [];

  return (
    <Pressable
      onPress={onToggle}
      style={({ pressed }) => [
        styles.row,
        pressed && styles.rowPressed,
        completed && styles.rowCompleted,
      ]}
      accessibilityRole="checkbox"
      accessibilityState={{ checked: completed }}
    >
      <View style={[styles.checkbox, completed && styles.checkboxOn]}>
        {completed ? (
          <Text style={styles.checkboxMark} accessibilityLabel="Checked">
            ✓
          </Text>
        ) : null}
      </View>
      <View style={styles.textCol}>
        <Text style={[styles.label, completed && styles.labelDone]}>{name}</Text>
        {detailLines.length > 0 ? (
          <View style={styles.detailBlock}>
            {detailLines.map((line, i) => (
              <Text
                key={i}
                style={[styles.detailLine, completed && styles.detailLineDone]}
              >
                {line}
              </Text>
            ))}
          </View>
        ) : null}
      </View>
    </Pressable>
  );
}

const styles = StyleSheet.create({
  row: {
    flexDirection: 'row',
    alignItems: 'flex-start',
    paddingVertical: 14,
    paddingHorizontal: 16,
    borderRadius: V.boxRadius,
    borderWidth: V.outlineWidth,
    borderColor: V.borderMuted,
    backgroundColor: V.bgElevated,
    marginBottom: 10,
  },
  rowPressed: {
    opacity: 0.88,
  },
  rowCompleted: {
    backgroundColor: V.surfaceComplete,
    borderColor: V.borderHairline,
  },
  checkbox: {
    width: 22,
    height: 22,
    borderRadius: V.boxRadius,
    borderWidth: V.outlineWidth,
    borderColor: V.textSecondary,
    marginRight: 12,
    marginTop: 2,
    justifyContent: 'center',
    alignItems: 'center',
  },
  checkboxOn: {
    borderColor: V.accent,
    backgroundColor: 'transparent',
  },
  checkboxMark: {
    color: V.accent,
    fontSize: 14,
    fontWeight: '700',
    lineHeight: 15,
    marginTop: -1,
  },
  textCol: {
    flex: 1,
  },
  label: {
    fontSize: 17,
    color: V.text,
    letterSpacing: -0.24,
    fontWeight: '600',
  },
  labelDone: {
    textDecorationLine: 'line-through',
    color: V.textTertiary,
  },
  detailBlock: {
    marginTop: 6,
  },
  detailLine: {
    fontSize: 14,
    color: V.textSecondary,
    lineHeight: 20,
  },
  detailLineDone: {
    color: V.textDim,
  },
});
